import * as XLSX from 'xlsx';
import { Customer } from './types';

export const VND_MULTIPLIER = 1; // Sử dụng giá trị thực, không nhân 1000 nữa

export const formatCurrency = (value: number) => {
  if (value === undefined || value === null) return "0 đ";
  // Đảm bảo giá trị là số nguyên và sử dụng định dạng vi-VN để có dấu chấm phân cách
  const realVnd = Math.round(value);
  return realVnd.toLocaleString('vi-VN') + ' đ';
};

export const normalizeString = (str: string): string => {
  if (!str) return "";
  return str
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/Đ/g, "d")
    .replace(/[^a-z0-9 ]/g, "")
    .trim();
};

export const normalizePhoneForZalo = (phone: any): string => {
  let p = String(phone || "").replace(/[^0-9]/g, '');
  if (p.startsWith('0')) {
    p = '84' + p.substring(1);
  } else if (p.length === 9 && !p.startsWith('84')) {
    p = '84' + p;
  }
  return p;
};

export const generateVietQrUrl = (bankId: string, accountNo: string, amount: number, customerName: string) => {
  const amountVnd = Math.max(0, Math.round(amount));
  const cleanName = normalizeString(customerName).toUpperCase();
  const addInfo = `TT Nuoc ${cleanName}`.substring(0, 25);
  return `https://img.vietqr.io/image/${bankId}-${accountNo}-compact.png?amount=${amountVnd}&addInfo=${encodeURIComponent(addInfo)}`;
};

export const exportToExcel = (customers: Customer[], fileName: string = 'Bao_Cao_Tien_Nuoc') => {
  const header = [
    "STT", "KHÁCH HÀNG", "ĐỊA CHỈ", "ĐIỆN THOẠI", 
    "CHỈ SỐ MỚI", "CHỈ SỐ CŨ", "SỐ LƯỢNG (M3)", "THÀNH TIỀN", 
    "NỢ KỲ TRƯỚC", "THANH TOÁN", "NỢ LẠI", "ĐÃ VÀO ZALO"
  ];

  const formatZero = (val: number) => (val === 0 ? "" : val);

  const data = customers.sort((a, b) => a.stt - b.stt).map(c => {
    const displayBalance = c.newIndex > 0 ? c.balance : 0;

    return [
      c.stt, 
      c.name, 
      c.address, 
      c.phone, 
      formatZero(c.newIndex),
      c.oldIndex,
      formatZero(c.volume),
      formatZero(Math.round(c.amount)),
      Math.round(c.oldDebt),
      formatZero(Math.round(c.paid)),
      formatZero(Math.round(displayBalance)),
      c.isZalo ? "X" : ""
    ];
  });

  const ws = XLSX.utils.aoa_to_sheet([header, ...data]);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Dữ liệu");
  XLSX.writeFile(wb, `${fileName}_${new Date().toISOString().slice(0, 10)}.xlsx`);
};

const parseExcelNum = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  // Loại bỏ dấu chấm (phân cách hàng nghìn ở VN) và thay dấu phẩy bằng dấu chấm nếu có
  const clean = String(val).replace(/\./g, '').replace(/,/g, '.').replace(/[^0-9.]/g, '');
  return parseFloat(clean) || 0;
};

export const parseExcelFile = async (file: File, listType: 'list1' | 'list2', rate: number): Promise<Customer[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const worksheet = workbook.Sheets[workbook.SheetNames[0]];
        const jsonData: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: "" });

        let startRow = 0;
        for (let r = 0; r < Math.min(jsonData.length, 15); r++) {
          const cell0 = String(jsonData[r][0]).toUpperCase();
          const cell1 = String(jsonData[r][1]).toUpperCase();
          if (cell0 === "STT" || cell1 === "KHÁCH HÀNG") {
            startRow = r + 1;
            break;
          }
        }

        const result: Customer[] = [];
        for (let i = startRow; i < jsonData.length; i++) {
          const row = jsonData[i];
          const sttRaw = String(row[0]).trim();
          if (!sttRaw || isNaN(parseInt(sttRaw))) continue;

          const stt = parseInt(sttRaw);
          const name = String(row[1] || "").trim();
          if (name.toUpperCase().includes("TỔNG")) continue;

          const address = String(row[2] || "").trim();
          const phone = String(row[3] || "").replace(/[^0-9]/g, '');
          const newIndex = parseExcelNum(row[4]);
          const oldIndex = parseExcelNum(row[5]);
          const oldDebt = parseExcelNum(row[8]);
          const paid = parseExcelNum(row[9]);

          const volume = (newIndex > 0 && newIndex >= oldIndex) ? (newIndex - oldIndex) : 0;
          const amount = volume * rate;
          const balance = newIndex > 0 ? (amount + oldDebt) - paid : 0;

          result.push({
            id: `xl-${stt}-${listType}`,
            stt, name, address, phone, newIndex, oldIndex,
            volume, amount, oldDebt, paid, balance, listType,
            status: balance <= 0 && newIndex > 0 ? 'paid' : 'unpaid',
            isZalo: String(row[11]).toUpperCase() === "X"
          });
        }
        resolve(result);
      } catch (err) { reject(err); }
    };
    reader.readAsArrayBuffer(file);
  });
};

